249	
250	def _get_phase_status(grouped: dict) -> dict[str, str]:
251	    """Determine status (done/active/pending) for each pipeline phase."""
252	    node_starts = {e.get("node") for e in grouped.get("node_start", [])}
253	    node_ends = {e.get("node") for e in grouped.get("node_end", [])}
254	
255	    status = {}
256	    for phase in _PHASE_ORDER:
257	        if phase in node_ends:
258	            status[phase] = "done"
259	        elif phase in node_starts:
260	            status[phase] = "active"
261	        else:
262	            status[phase] = "pending"
263	    return status
