1263	def _build_js() -> str:
1264	    """JS for scroll spy, evidence filtering, STORM tab switching."""
1265	    return """
1266	document.addEventListener('DOMContentLoaded', function() {
1267	  // --- Scroll spy ---
1268	  var sections = document.querySelectorAll('.section[id]');
1269	  var navLinks = document.querySelectorAll('.sidebar a[data-section]');
1270	  var centerPanel = document.querySelector('.center');
1271	
1272	  if (centerPanel && sections.length > 0) {
1273	    centerPanel.addEventListener('scroll', function() {
1274	      var scrollPos = centerPanel.scrollTop + 80;
1275	      var current = '';
1276	      sections.forEach(function(s) {
1277	        if (s.offsetTop <= scrollPos) {
1278	          current = s.id;
1279	        }
1280	      });
1281	      navLinks.forEach(function(a) {
1282	        a.classList.remove('active');
1283	        if (a.getAttribute('data-section') === current) {
1284	          a.classList.add('active');
1285	        }
1286	      });
1287	    });
1288	  }
1289	
1290	  // --- Sidebar nav click ---
1291	  navLinks.forEach(function(a) {
1292	    a.addEventListener('click', function(e) {
1293	      e.preventDefault();
1294	      var target = document.getElementById(this.getAttribute('data-section'));
1295	      if (target && centerPanel) {
1296	        centerPanel.scrollTo({ top: target.offsetTop - 20, behavior: 'smooth' });
1297	      }
1298	    });
1299	  });
1300	
1301	  // --- Evidence filter ---
1302	  var filterSelect = document.getElementById('evidence-filter');
1303	  if (filterSelect) {
1304	    filterSelect.addEventListener('change', function() {
1305	      var val = this.value;
1306	      var cards = document.querySelectorAll('.evidence-card[data-tier]');
1307	      cards.forEach(function(card) {
1308	        if (val === 'all' || card.getAttribute('data-tier') === val) {
1309	          card.style.display = '';
1310	        } else {
1311	          card.style.display = 'none';
1312	        }
1313	      });
1314	      // Update count
1315	      var visible = document.querySelectorAll('.evidence-card[data-tier]:not([style*="display: none"])').length;
1316	      var countEl = document.getElementById('evidence-visible-count');
1317	      if (countEl) countEl.textContent = visible;
1318	    });
1319	  }
1320	
1321	  // --- STORM persona tabs ---
1322	  var personaTabs = document.querySelectorAll('.storm-persona-tab');
1323	  personaTabs.forEach(function(tab) {
1324	    tab.addEventListener('click', function() {
1325	      var persona = this.getAttribute('data-persona');
1326	      // Toggle active tab
1327	      personaTabs.forEach(function(t) { t.classList.remove('active'); });
1328	      this.classList.add('active');
1329	      // Toggle conversation
1330	      var convos = document.querySelectorAll('.storm-conversation');
1331	      convos.forEach(function(c) {
1332	        if (c.getAttribute('data-persona') === persona) {
1333	          c.classList.add('active');
1334	        } else {
1335	          c.classList.remove('active');
1336	        }
1337	      });
1338	    });
1339	  });
1340	});
1341	"""
