1344	# ---------------------------------------------------------------------------
1345	# SVG Faithfulness Gauge
1346	# ---------------------------------------------------------------------------
1347	
1348	def _build_faith_gauge_svg(faith_pct: float) -> str:
1349	    """Generate an SVG circular gauge for faithfulness percentage.
1350	
1351	    Args:
1352	        faith_pct: Faithfulness as 0-100 percentage.
1353	    """
1354	    # SVG parameters
1355	    size = 80
1356	    cx = cy = size / 2
1357	    r = 32
1358	    stroke_width = 6
1359	    circumference = 2 * math.pi * r
1360	    offset = circumference * (1 - faith_pct / 100)
1361	
1362	    # Color based on value
1363	    if faith_pct >= 80:
1364	        color = "#22c55e"
1365	    elif faith_pct >= 60:
1366	        color = "#f59e0b"
1367	    else:
1368	        color = "#ef4444"
1369	
1370	    return f"""<svg class="faith-gauge" width="{size}" height="{size}" viewBox="0 0 {size} {size}">
1371	      <circle cx="{cx}" cy="{cy}" r="{r}" fill="none" stroke="#262626" stroke-width="{stroke_width}"/>
1372	      <circle cx="{cx}" cy="{cy}" r="{r}" fill="none" stroke="{color}" stroke-width="{stroke_width}"
1373	              stroke-dasharray="{circumference:.1f}" stroke-dashoffset="{offset:.1f}"
1374	              stroke-linecap="round" transform="rotate(-90 {cx} {cy})"
1375	              style="transition: stroke-dashoffset 0.8s ease;"/>
1376	      <text x="{cx}" y="{cy + 1}" text-anchor="middle" dominant-baseline="middle"
1377	            font-family="Inter, sans-serif" font-size="14" font-weight="700" fill="{color}">
1378	        {faith_pct:.0f}%
1379	      </text>
1380	    </svg>"""
