1571	def _section_evidence_funnel(grouped: dict) -> str:
1572	    """Visual evidence funnel chart with gradient bars."""
1573	    evidence_events = grouped.get("evidence", [])
1574	
1575	    # Aggregate counts by action
1576	    action_counts: dict[str, int] = defaultdict(int)
1577	    for ev in evidence_events:
1578	        action = ev.get("action", "unknown")
1579	        count = ev.get("count", 0)
1580	        if count > action_counts[action]:
1581	            action_counts[action] = count
1582	
1583	    # Funnel stages in order
1584	    funnel_stages = [
1585	        ("relevance_scored", "Searched", "#3b82f6"),
1586	        ("offtopic_filtered", "On-topic", "#6366f1"),
1587	        ("extracted", "Extracted", "#8b5cf6"),
1588	        ("dedup_summary", "Deduplicated", "#a855f7"),
1589	        ("verified", "Verified", "#22c55e"),
1590	        ("clustering", "Clustered", "#14b8a6"),
1591	        ("citation_audit", "Cited", "#06b6d4"),
1592	        ("report_assembled", "Final", "#0ea5e9"),
1593	    ]
1594	
1595	    active_stages = []
1596	    for action, label, color in funnel_stages:
1597	        count = action_counts.get(action, 0)
1598	        if count > 0:
1599	            active_stages.append((action, label, color, count))
1600	
1601	    if not active_stages:
1602	        return ""
1603	
1604	    # Use first stage as reference for funnel shape.
1605	    # Skip any later stage whose count exceeds the first by >2x
1606	    # (accumulated totals across iterations, not a real funnel step).
1607	    first_count = active_stages[0][3]
1608	    filtered_stages = []
1609	    for stage in active_stages:
1610	        if stage[3] > first_count * 2 and stage != active_stages[0]:
1611	            continue  # skip inflated accumulated counts
1612	        filtered_stages.append(stage)
1613	    active_stages = filtered_stages if filtered_stages else active_stages
1614	    max_count = active_stages[0][3] if active_stages else 1
1615	
1616	    funnel_html = '<div class="funnel">'
1617	    for action, label, color, count in active_stages:
1618	        pct = (min(count, max_count) / max_count) * 100 if max_count > 0 else 0
1619	        pct_of_first = (count / active_stages[0][3]) * 100 if active_stages[0][3] > 0 else 0
1620	        funnel_html += f"""
1621	        <div class="funnel-row">
1622	          <span class="funnel-label">{label}</span>
1623	          <div class="funnel-bar-track">
1624	            <div class="funnel-bar-fill" style="width: {max(pct, 5):.0f}%; background: {color};">{count:,}</div>
1625	          </div>
1626	          <span class="funnel-pct">{pct_of_first:.0f}%</span>
1627	        </div>"""
1628	    funnel_html += '</div>'
1629	
1630	    return f"""
1631	    <div class="section" id="sec-funnel">
1632	      <div class="section-header">
1633	        <h2>Evidence Funnel</h2>
1634	        <span class="section-badge">{len(evidence_events)} events</span>
1635	      </div>
1636	      {funnel_html}
1637	    </div>"""
